/* script.min.js - minifié */ !(function () {
  'use strict';
  var e = document.getElementById('nav-hamburger'),
    t = document.getElementById('nav-mobile');
  if (e && t) {
    e.addEventListener('click', function () {
      (e.classList.toggle('active'), t.classList.toggle('open'));
    });
    var n = t.querySelectorAll('a');
    n.forEach(function (t) {
      t.addEventListener('click', function () {
        (e.classList.remove('active'), t.classList.remove('open'));
      });
    });
  }
})();
